# Minimal skeleton illustrating components
class ModuleRegistry:
    def __init__(self):
        self._modules = {}
    def register(self, name, fn):
        self._modules[name] = fn
    def build(self, order, base=""):
        prompt = base
        for name in order:
            prompt += self._modules[name](prompt)
        return prompt

class GuardInjector:
    def inject(self, prompt, policy):
        guard = policy.get("guard", "")
        return f"{guard}\n{prompt}"

